import React, { useState } from "react";
import axios from "axios";
import "bootstrap/dist/css/bootstrap.min.css";
import { useNavigate } from "react-router-dom";

export default function Login() {
  const [usuario, setUsuario] = useState(""); // usuario o correo
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");
    setLoading(true);

    try {
      const res = await axios.post(
        "http://localhost:5000/api/usuarios/login",
        {
          usuario, // 🔥 puede ser username o correo
          password,
        }
      );

      if (res.data.usuario) {
        localStorage.setItem("usuarioId", res.data.usuario.id);
        localStorage.setItem("rol", res.data.usuario.rol);
        localStorage.setItem("nombre", res.data.usuario.nombre);

        navigate("/Dashboard");
      } else {
        setError("Credenciales incorrectas");
      }
    } catch (err) {
      console.error(err);
      setError("Usuario o contraseña incorrectos");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="container d-flex align-items-center justify-content-center vh-100 bg-light">
      <div
        className="card shadow-lg p-4"
        style={{ maxWidth: "420px", width: "100%", borderRadius: "12px" }}
      >
        <h4 className="text-center mb-3 fw-bold">
          Sistema de Ventas
        </h4>

        <p className="text-center text-muted mb-4">
          Inicia sesión para continuar
        </p>

        {error && (
          <div className="alert alert-danger text-center py-2">
            {error}
          </div>
        )}

        <form onSubmit={handleSubmit}>
          {/* Usuario */}
          <div className="mb-3">
            <label className="form-label">
              Usuario o correo
            </label>
            <input
              type="text"
              className="form-control"
              placeholder=""
              value={usuario}
              onChange={(e) => setUsuario(e.target.value)}
              required
            />
          </div>

          {/* Contraseña */}
          <div className="mb-2">
            <label className="form-label">
              Contraseña
            </label>
            <input
              type="password"
              className="form-control"
              placeholder="••••••••"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
            />
          </div>

          {/* Olvidaste contraseña */}
          <div className="text-end mb-3">
            <button
              type="button"
              className="btn btn-link p-0"
              style={{ fontSize: "0.9rem" }}
              onClick={() => navigate("/recuperar-password")}
            >
              ¿Olvidaste tu contraseña?
            </button>
          </div>

          <button
            type="submit"
            className="btn btn-primary w-100"
            disabled={loading}
          >
            {loading ? "Ingresando..." : "Iniciar sesión"}
          </button>
        </form>

        {/* Credenciales demo (solo para pruebas) */}
        <div className="mt-4 text-muted text-center" style={{ fontSize: "0.85rem" }}>
          <strong>Demo:</strong><br />
          Admin <br />
          12345
        </div>
      </div>
    </div>
  );
}
